SELECT asset_id, filename, page_count, char_count, extraction_method, extraction_error, sampled_at,
       left(extracted_text, 800) AS text_head
FROM pdf_text_samples
WHERE asset_id IN ('b6e9904f-0da5-4bde-aef6-ba2f0d20b8d7','ce7e3857-7b58-4f96-9c0e-09f60c9a019c')
ORDER BY sampled_at DESC;

SELECT * FROM sku_files_used WHERE sku = 'AAE26DYCR01' ORDER BY file_name;

SELECT count(*) AS samples_for_these_pdfs
FROM pdf_text_samples
WHERE asset_id IN ('b6e9904f-0da5-4bde-aef6-ba2f0d20b8d7','ce7e3857-7b58-4f96-9c0e-09f60c9a019c');

SELECT count(*) AS total_samples,
       count(*) FILTER (WHERE extracted_text IS NOT NULL AND char_count > 0) AS with_text,
       count(*) FILTER (WHERE extraction_error IS NOT NULL) AS with_error,
       min(sampled_at) AS earliest, max(sampled_at) AS latest
FROM pdf_text_samples;

SELECT count(*) AS total_pdf_assets FROM assets WHERE file_type = 'pdf';
SELECT count(*) AS total_sku_files_used FROM sku_files_used;

SELECT proname, pg_get_functiondef(oid)
FROM pg_proc
WHERE proname IN ('claim_pdf_backfill_batch','backfill_pdf_files_used','resolve_sku_files_used','parse_pdf_files_used');

