1	/**
2	 * PDF Backfill Worker
3	 *
4	 * Processes every PDF asset in the library that hasn't been sampled yet.
5	 * Runs as a self-driven claim loop: claim 25 → process → commit → repeat.
6	 *
7	 * Key differences from runPdfTextSample (sample mode):
8	 *   - Fetches its own work batches via claim-pdf-backfill-batch (no pre-loaded list)
9	 *   - Submits results per-batch instead of accumulating all at the end
10	 *   - Always generates an 800px JPEG thumbnail for assets that are missing one
11	 *   - FILES USED parsing happens server-side in TypeScript (no PL/pgSQL timeout)
12	 *   - Stops cleanly when status becomes "paused" or "completed"
13	 */
14	
15	import { readFile, stat } from "node:fs/promises";
16	import { join } from "node:path";
17	import sharp from "sharp";
18	import { logger } from "./logger.js";
19	import * as api from "./api-client.js";
20	import { uploadThumbnail, uploadPdfPage } from "./uploader.js";
21	import * as mupdf from "mupdf";
22	import { createWorker } from "tesseract.js";
23	import Anthropic from "@anthropic-ai/sdk";
24	import type { AiConfig } from "./pdf-text-sampler.js";
25	import { isAiWithoutPdfCompat } from "./thumbnailer.js";
26	
27	const PDF_SIZE_LIMIT_BYTES = 100 * 1024 * 1024;
28	const THUMBNAIL_WIDTH = 800;
29	
30	// ── AI vision (mirrors pdf-text-sampler.ts) ───────────────────────────────────
31	
32	async function callAiVision(pngBuffer: Buffer, aiConfig: AiConfig): Promise<string> {
33	  const modelId = aiConfig.pdf_extraction?.ai_vision_model_id;
34	  if (!modelId) return "";
35	
36	  const modelDef = aiConfig.models.find((m) => m.id === modelId);
37	  if (!modelDef || !modelDef.capabilities.includes("vision")) return "";
38	
39	  const base64 = pngBuffer.toString("base64");
40	
41	  if (modelDef.provider === "google") {
42	    if (!aiConfig.googleApiKey) return "";
43	    const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelDef.apiModel}:generateContent?key=${aiConfig.googleApiKey}`;
44	    const res = await fetch(url, {
45	      method: "POST",
46	      headers: { "Content-Type": "application/json" },
47	      signal: AbortSignal.timeout(60_000),
48	      body: JSON.stringify({
49	        contents: [{ role: "user", parts: [
50	          { inlineData: { mimeType: "image/png", data: base64 } },
51	          { text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
52	        ]}],
53	      }),
54	    });
55	    if (!res.ok) throw new Error(`Gemini API ${res.status}`);
56	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
57	    const data = await res.json() as any;
58	    return (data?.candidates?.[0]?.content?.parts?.[0]?.text as string || "").trim();
59	  }
60	
61	  if (modelDef.provider === "anthropic") {
62	    if (!aiConfig.anthropicApiKey) return "";
63	    const anthropic = new Anthropic({ apiKey: aiConfig.anthropicApiKey });
64	    const aiResponse = await anthropic.messages.create({
65	      model: modelDef.apiModel,
66	      max_tokens: 2048,
67	      messages: [{ role: "user", content: [
68	        { type: "image", source: { type: "base64", media_type: "image/png", data: base64 } },
69	        { type: "text", text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
70	      ]}],
71	    });
72	    const first = aiResponse.content[0];
73	    return (first.type === "text" ? first.text : "").trim();
74	  }
75	
76	  return "";
77	}
78	
79	// ── Process a single PDF ──────────────────────────────────────────────────────
80	
81	async function processOne(
82	  asset: api.BackfillAsset,
83	  fullPath: string,
84	  aiConfig: AiConfig,
85	): Promise<api.BackfillResult> {
86	  const fileStat = await stat(fullPath);
87	  if (fileStat.size > PDF_SIZE_LIMIT_BYTES) {
88	    return {
89	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
90	      extraction_method: "skipped", extracted_text: null,
91	      page_count: null, char_count: 0, extraction_error: null,
92	      sample_thumbnail_url: null, asset_thumbnail_url: null,
93	    };
94	  }
95	
96	  if (asset.filename.toLowerCase().endsWith(".ai")) {
97	    const isSentinel = await isAiWithoutPdfCompat(fullPath);
98	    if (isSentinel) {
99	      const sentinelText = "This is an Adobe® Illustrator® File that was saved without PDF Content.";
100	      return {
101	        asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
102	        extraction_method: "pdf_text", extracted_text: sentinelText,
103	        page_count: 1, char_count: sentinelText.length, extraction_error: null,
104	        sample_thumbnail_url: null, asset_thumbnail_url: null,
105	      };
106	    }
107	  }
108	
109	  const buffer = await readFile(fullPath);
110	  let rawText = "";
111	  let numPages: number | null = null;
112	  let mupdfDoc: ReturnType<typeof mupdf.Document.openDocument> | null = null;
113	
114	  // Step 1: mupdf text extraction
115	  try {
116	    mupdfDoc = mupdf.Document.openDocument(buffer, "application/pdf");
117	    numPages = mupdfDoc.countPages();
118	    const parts: string[] = [];
119	    for (let p = 0; p < numPages; p++) {
120	      parts.push(mupdfDoc.loadPage(p).toStructuredText("preserve-whitespace").asText());
121	    }
122	    rawText = parts.join("\n").trim();
123	  } catch (e) {
124	    logger.warn("PDF backfill: mupdf text failed", { filename: asset.filename, error: (e as Error).message });
125	  }
126	
127	  // Step 2: render page 0 — always when thumbnail needed, or when text < 100 chars (OCR fallback)
128	  let pngBuffer: Buffer | null = null;
129	  let sampleThumbnailUrl: string | null = null;
130	  let assetThumbnailUrl: string | null = null;
131	
132	  if (asset.needs_thumbnail || rawText.length < 100) {
133	    try {
134	      if (!mupdfDoc) {
135	        mupdfDoc = mupdf.Document.openDocument(buffer, "application/pdf");
136	        numPages = mupdfDoc.countPages();
137	      }
138	      const page = mupdfDoc.loadPage(0);
139	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
140	      const pixmap = page.toPixmap([2, 0, 0, 2, 0, 0] as any, (mupdf as any).ColorSpace.DeviceRGB, false);
141	      pngBuffer = Buffer.from(pixmap.asPNG() as Uint8Array);
142	
143	      // Upload hi-res page image (for pdf_text_samples.thumbnail_url — OCR/AI input)
144	      try {
145	        sampleThumbnailUrl = await uploadPdfPage(asset.id, 0, pngBuffer);
146	      } catch (e) {
147	        logger.warn("PDF backfill: page upload failed (non-fatal)", { filename: asset.filename, error: (e as Error).message });
148	      }
149	
150	      // Generate 800px JPEG thumbnail for assets.thumbnail_url
151	      if (asset.needs_thumbnail) {
152	        try {
153	          const jpegBuffer = await sharp(pngBuffer)
154	            .resize({ width: THUMBNAIL_WIDTH, withoutEnlargement: true })
155	            .jpeg({ quality: 85 })
156	            .toBuffer();
157	          assetThumbnailUrl = await uploadThumbnail(asset.id, jpegBuffer);
158	        } catch (e) {
159	          logger.warn("PDF backfill: thumbnail generate failed (non-fatal)", { filename: asset.filename, error: (e as Error).message });
160	        }
161	      }
162	    } catch (e) {
163	      logger.warn("PDF backfill: page render failed", { filename: asset.filename, error: (e as Error).message });
164	    }
165	  }
166	
167	  // Fast path: mupdf text was sufficient
168	  if (rawText.length >= 100) {
169	    return {
170	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
171	      extraction_method: "pdf_text", extracted_text: rawText,
172	      page_count: numPages, char_count: rawText.length, extraction_error: null,
173	      sample_thumbnail_url: sampleThumbnailUrl, asset_thumbnail_url: assetThumbnailUrl,
174	    };
175	  }
176	
177	  // Step 3: OCR via tesseract.js
178	  let ocrText = "";
179	  if (pngBuffer) {
180	    try {
181	      const worker = await createWorker("eng");
182	      const result = await worker.recognize(pngBuffer);
183	      await worker.terminate();
184	      ocrText = result.data.text.trim();
185	    } catch (e) {
186	      logger.warn("PDF backfill: OCR failed", { filename: asset.filename, error: (e as Error).message });
187	    }
188	  }
189	
190	  if (ocrText.length >= 100) {
191	    return {
192	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
193	      extraction_method: "ocr_text", extracted_text: ocrText,
194	      page_count: numPages, char_count: ocrText.length, extraction_error: null,
195	      sample_thumbnail_url: sampleThumbnailUrl, asset_thumbnail_url: assetThumbnailUrl,
196	    };
197	  }
198	
199	  // Step 4: AI vision
200	  let aiText = "";
201	  let aiErr = "";
202	  if (pngBuffer) {
203	    try {
204	      aiText = await callAiVision(pngBuffer, aiConfig);
205	    } catch (e) {
206	      aiErr = (e as Error).message;
207	    }
208	  }
209	
210	  if (aiText.length > 0) {
211	    return {
212	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
213	      extraction_method: "ai_vision", extracted_text: aiText,
214	      page_count: numPages, char_count: aiText.length, extraction_error: null,
215	      sample_thumbnail_url: sampleThumbnailUrl, asset_thumbnail_url: assetThumbnailUrl,
216	    };
217	  }
218	
219	  const finalText = ocrText.length > 0 ? ocrText : rawText;
220	  const finalCount = finalText.length;
221	  const method = finalCount >= 100 ? "pdf_text" : finalCount > 0 ? "likely_scanned" : "failed";
222	
223	  return {
224	    asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
225	    extraction_method: method,
226	    extracted_text: finalCount > 0 ? finalText : null,
227	    page_count: numPages, char_count: finalCount,
228	    extraction_error: aiErr ? aiErr.slice(0, 500) : null,
229	    sample_thumbnail_url: sampleThumbnailUrl, asset_thumbnail_url: assetThumbnailUrl,
230	  };
231	}
232	
233	// ── Main backfill loop ────────────────────────────────────────────────────────
234	
235	export async function runPdfBackfill(
236	  mountRoot: string,
237	  aiConfig: AiConfig,
238	): Promise<void> {
239	  logger.info("PDF backfill: starting");
240	  let totalProcessed = 0;
241	
242	  for (;;) {
243	    const batch = await api.claimPdfBackfillBatch();
244	
245	    if (batch.status !== "running") {
246	      logger.info("PDF backfill: stopped by server", { status: batch.status });
247	      break;
248	    }
249	
250	    if (batch.assets.length === 0) {
251	      logger.info("PDF backfill: no more assets — complete", { totalProcessed });
252	      break;
253	    }
254	
255	    logger.info("PDF backfill: batch claimed", { count: batch.assets.length, remaining: batch.remaining });
256	
257	    const results: api.BackfillResult[] = [];
258	
259	    for (let i = 0; i < batch.assets.length; i++) {
260	      const asset = batch.assets[i];
261	      await api.reportPdfBackfillProgress(totalProcessed + i, batch.total, asset.filename, "processing");
262	
263	      try {
264	        const result = await processOne(asset, join(mountRoot, asset.relative_path), aiConfig);
265	        results.push(result);
266	        logger.info("PDF backfill: file done", {
267	          filename: asset.filename,
268	          method: result.extraction_method,
269	          chars: result.char_count,
270	          thumbnail: !!result.asset_thumbnail_url,
271	        });
272	      } catch (e) {
273	        const errMsg = (e as Error).message;
274	        logger.warn("PDF backfill: file failed", { filename: asset.filename, error: errMsg });
275	        results.push({
276	          asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
277	          extraction_method: "failed", extracted_text: null,
278	          page_count: null, char_count: 0, extraction_error: errMsg.slice(0, 500),
279	          sample_thumbnail_url: null, asset_thumbnail_url: null,
280	        });
281	      }
282	    }
283	
284	    const { remaining } = await api.completePdfBackfillBatch(results);
285	    totalProcessed += results.length;
286	
287	    await api.reportPdfBackfillProgress(totalProcessed, batch.total, null, "idle");
288	    logger.info("PDF backfill: batch committed", { totalProcessed, remaining });
289	
290	    if (remaining <= 0) {
291	      logger.info("PDF backfill: all files processed", { totalProcessed });
292	      break;
293	    }
294	  }
295	
296	  logger.info("PDF backfill: loop exited", { totalProcessed });
297	}
298

