103	// ── Auth: JWT validation only (any authenticated user) ──────────────
104	
105	async function authenticateUser(
106	  req: Request,
107	): Promise<{ userId: string } | Response> {
108	  const authHeader = req.headers.get("Authorization");
109	  if (!authHeader?.startsWith("Bearer ")) {
110	    return err("Missing or invalid Authorization header", 401);
111	  }
112	
113	  const token = authHeader.replace("Bearer ", "");
114	
115	  // Service role key bypass — allows server-to-server calls (e.g., Railway worker)
116	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
117	  if (serviceRoleKey && token === serviceRoleKey) {
118	    return { userId: "system" };
119	  }
120	
121	  const anonClient = createClient(
122	    Deno.env.get("SUPABASE_URL")!,
123	    Deno.env.get("SUPABASE_ANON_KEY")!,
124	    { global: { headers: { Authorization: authHeader } } },
125	  );
126	
127	  try {
128	    let sub: string | undefined;
129	    const { data: { user }, error: userError } = await anonClient.auth.getUser(token);
130	    if (userError || !user?.id) {
131	      if (typeof anonClient.auth.getClaims === "function") {
132	        const { data, error: claimsError } = await anonClient.auth.getClaims(token);
133	        if (!claimsError && data?.claims?.sub) {
134	          sub = data.claims.sub as string;
135	        }
136	      }
137	      if (!sub) {
138	        console.error("Auth failed — getUser:", userError);
139	        return err("Invalid or expired token", 401);
140	      }
141	    } else {
142	      sub = user.id;
143	    }
144	    console.log("Authenticated userId:", sub);
145	    return { userId: sub };
146	  } catch (e) {
147	    console.error("Token validation error:", e);
148	    return err("Invalid or expired token", 401);
149	  }
150	}
